// hooks/useNetworkQuality.ts (extended from earlier)
import { useEffect, useState } from 'react';

type Quality = 'high' | 'medium' | 'low' | 'unknown';

export function useNetworkQuality(): Quality {
  const [q, setQ] = useState<Quality>('unknown');
  useEffect(() => {
    // @ts-expect-error
    const conn = navigator.connection;
    if (!conn) { setQ('high'); return; }
    const update = () => {
      if (conn.saveData) { setQ('low'); return; }
      if (conn.effectiveType === '4g') setQ('high');
      else if (conn.effectiveType === '3g') setQ('medium');
      else setQ('low');
    };
    update();
    conn.addEventListener?.('change', update);
    return () => conn.removeEventListener?.('change', update);
  }, []);
  return q;
}

// components/AdaptiveVideo.tsx
import { useNetworkQuality } from '@/hooks/useNetworkQuality';

export function AdaptiveVideo({ sources }: { sources: { high: string; medium: string; low: string; poster: string } }) {
  const q = useNetworkQuality();
  const src = q === 'high' ? sources.high : q === 'medium' ? sources.medium : sources.low;

  if (q === 'unknown') {
    return <img src={sources.poster} alt="" className="w-full aspect-video object-cover" />;
  }

  return (
    <video
      src={src}
      poster={sources.poster}
      controls
      preload="metadata"
      className="w-full aspect-video bg-black"
    />
  );
}

// components/OverflowTabs.tsx
'use client';
import { useEffect, useRef, useState } from 'react';
import { MoreHorizontal } from 'lucide-react';

type Tab = { id: string; label: string };

export function OverflowTabs({ tabs, active, onChange }: { tabs: Tab[]; active: string; onChange: (id: string) => void }) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [visibleCount, setVisibleCount] = useState(tabs.length);
  const [moreOpen, setMoreOpen] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    const ro = new ResizeObserver(() => {
      const container = containerRef.current!;
      const totalW = container.offsetWidth - 50; // leave room for More
      const tabEls = Array.from(container.querySelectorAll<HTMLElement>('[data-tab]'));
      let used = 0;
      let count = 0;
      for (const el of tabEls) {
        used += el.offsetWidth + 8; // gap
        if (used > totalW) break;
        count++;
      }
      setVisibleCount(Math.max(1, count));
    });
    ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, [tabs]);

  const visible = tabs.slice(0, visibleCount);
  const overflow = tabs.slice(visibleCount);

  return (
    <div ref={containerRef} className="flex items-center gap-2 border-b">
      {visible.map((t) => (
        <button
          key={t.id}
          data-tab
          onClick={() => onChange(t.id)}
          aria-selected={active === t.id}
          role="tab"
          className={`
            min-h-11 px-3 text-sm font-medium border-b-2 -mb-px
            ${active === t.id ? 'border-blue-500 text-blue-700' : 'border-transparent text-neutral-600'}
          `}
        >{t.label}</button>
      ))}
      {overflow.length > 0 && (
        <div className="relative">
          <button
            type="button"
            onClick={() => setMoreOpen((o) => !o)}
            aria-label="More tabs"
            aria-expanded={moreOpen}
            className="flex h-11 w-11 items-center justify-center"
          ><MoreHorizontal className="h-5 w-5" /></button>
          {moreOpen && (
            <div role="menu" className="absolute right-0 top-full mt-1 z-30 min-w-[10rem] rounded-md border bg-white shadow-lg py-1">
              {overflow.map((t) => (
                <button
                  key={t.id}
                  role="menuitem"
                  onClick={() => { onChange(t.id); setMoreOpen(false); }}
                  className={`block w-full px-3 py-2 text-left text-sm ${active === t.id ? 'bg-blue-50 text-blue-900' : 'hover:bg-neutral-50'}`}
                >{t.label}</button>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

