import { useEffect, useState } from 'react';
import { Minus, Plus } from 'lucide-react';

const SIZES = ['0.875rem', '1rem', '1.125rem', '1.25rem', '1.5rem'];

export function ReaderControls() {
  const [idx, setIdx] = useState(1);

  useEffect(() => {
    const stored = localStorage.getItem('reader-font-idx');
    if (stored) setIdx(Number(stored));
  }, []);

  useEffect(() => {
    document.documentElement.style.setProperty('--reader-font-size', SIZES[idx]);
    localStorage.setItem('reader-font-idx', String(idx));
  }, [idx]);

  return (
    <div role="group" aria-label="Font size" className="flex items-center gap-1">
      <button
        type="button"
        onClick={() => setIdx(Math.max(0, idx - 1))}
        disabled={idx === 0}
        aria-label="Decrease font size"
        className="flex h-11 w-11 items-center justify-center rounded hover:bg-neutral-100 disabled:opacity-50"
      ><Minus className="h-4 w-4" /></button>
      <span aria-live="polite" className="text-sm font-medium tabular-nums w-12 text-center">{idx + 1}/{SIZES.length}</span>
      <button
        type="button"
        onClick={() => setIdx(Math.min(SIZES.length - 1, idx + 1))}
        disabled={idx === SIZES.length - 1}
        aria-label="Increase font size"
        className="flex h-11 w-11 items-center justify-center rounded hover:bg-neutral-100 disabled:opacity-50"
      ><Plus className="h-4 w-4" /></button>
    </div>
  );
}

