// hooks/useSafeAreaInsets.ts
import { useEffect, useState } from 'react';

type Insets = { top: number; right: number; bottom: number; left: number };

export function useSafeAreaInsets(): Insets {
  const [insets, setInsets] = useState<Insets>({ top: 0, right: 0, bottom: 0, left: 0 });

  useEffect(() => {
    const measure = () => {
      const probe = document.createElement('div');
      probe.style.cssText = `
        position: fixed; top: env(safe-area-inset-top); right: env(safe-area-inset-right);
        bottom: env(safe-area-inset-bottom); left: env(safe-area-inset-left);
        pointer-events: none; opacity: 0;
      `;
      document.body.appendChild(probe);
      const cs = getComputedStyle(probe);
      setInsets({
        top: parseFloat(cs.top) || 0,
        right: parseFloat(cs.right) || 0,
        bottom: parseFloat(cs.bottom) || 0,
        left: parseFloat(cs.left) || 0,
      });
      probe.remove();
    };
    measure();
    window.addEventListener('resize', measure);
    window.addEventListener('orientationchange', measure);
    return () => {
      window.removeEventListener('resize', measure);
      window.removeEventListener('orientationchange', measure);
    };
  }, []);

  return insets;
}

// components/SafeTooltip.tsx
import { useSafeAreaInsets } from '@/hooks/useSafeAreaInsets';
import { useState, useRef } from 'react';

export function SafeTooltip({ content, children }: { content: string; children: React.ReactNode }) {
  const insets = useSafeAreaInsets();
  const [pos, setPos] = useState<{ x: number; y: number } | null>(null);
  const ref = useRef<HTMLSpanElement>(null);

  const open = () => {
    if (!ref.current) return;
    const r = ref.current.getBoundingClientRect();
    const x = Math.max(insets.left + 8, Math.min(window.innerWidth - insets.right - 200, r.left));
    const y = Math.max(insets.top + 8, r.bottom + 4);
    setPos({ x, y });
  };

  return (
    <>
      <span ref={ref} onMouseEnter={open} onMouseLeave={() => setPos(null)}>{children}</span>
      {pos && (
        <div
          role="tooltip"
          className="fixed z-50 w-48 rounded bg-neutral-900 text-white text-xs p-2 shadow-lg"
          style={{ left: pos.x, top: pos.y }}
        >{content}</div>
      )}
    </>
  );
}

// components/PreservingCanvas.tsx
import { useEffect, useRef } from 'react';
import { useElementSize } from '@/hooks/useElementSize';
import { useDpr } from '@/hooks/useDpr';

export function PreservingCanvas() {
  const [containerRef, { width, height }] = useElementSize<HTMLDivElement>();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const dpr = useDpr();

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || width === 0) return;

    const ctx = canvas.getContext('2d')!;
    // Preserve content
    const oldW = canvas.width;
    const oldH = canvas.height;
    let savedData: ImageData | null = null;
    if (oldW > 0 && oldH > 0) {
      try { savedData = ctx.getImageData(0, 0, oldW, oldH); } catch {}
    }

    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;

    if (savedData) {
      // Create temp canvas to scale content
      const tmp = document.createElement('canvas');
      tmp.width = oldW;
      tmp.height = oldH;
      tmp.getContext('2d')!.putImageData(savedData, 0, 0);
      ctx.drawImage(tmp, 0, 0, width * dpr, height * dpr);
    }

    ctx.scale(dpr, dpr);
  }, [width, height, dpr]);

  return (
    <div ref={containerRef} className="relative h-dvh w-full bg-white">
      <canvas ref={canvasRef} className="block" />
    </div>
  );
}

