// Key principles:

// 1. Use matchMedia for layout (not UA sniffing)
// 2. Don't store viewport class globally — recompute via hook
// 3. Use sessionStorage for per-window state, localStorage for cross-window

// hooks/useWindowState.ts — example pattern
import { useEffect, useState } from 'react';

export function useWindowState<T>(key: string, initial: T): [T, (v: T) => void] {
  const [value, setValue] = useState<T>(() => {
    if (typeof window === 'undefined') return initial;
    try {
      const stored = sessionStorage.getItem(key);
      return stored ? JSON.parse(stored) : initial;
    } catch {
      return initial;
    }
  });

  useEffect(() => {
    try { sessionStorage.setItem(key, JSON.stringify(value)); } catch {}
  }, [key, value]);

  return [value, setValue];
}

