import { useState } from 'react';
import { ChevronRight, Folder, File } from 'lucide-react';

type Node = { id: string; name: string; type: 'folder' | 'file'; children?: Node[] };

export function TreeTable({ nodes }: { nodes: Node[] }) {
  return (
    <div className="@container/tree w-full">
      <ul role="tree">
        {nodes.map((n) => <TreeNode key={n.id} node={n} depth={0} />)}
      </ul>
    </div>
