}

function TreeNode({ node, depth }: { node: Node; depth: number }) {
  const [expanded, setExpanded] = useState(false);
  const Icon = node.type === 'folder' ? Folder : File;
  const isLeaf = node.type === 'file' || !node.children?.length;

  return (
    <li role="treeitem" aria-expanded={isLeaf ? undefined : expanded}>
      <button
        type="button"
        onClick={() => !isLeaf && setExpanded((e) => !e)}
        className="
          flex w-full items-center gap-2 min-h-11 hover:bg-neutral-50
        "
        style={{
          paddingLeft: `calc(${depth} * var(--tree-indent, 1rem) + 0.5rem)`,
        }}
      >
        {isLeaf ? (
          <span className="w-4" />
        ) : (
          <ChevronRight className={`h-4 w-4 transition-transform ${expanded ? 'rotate-90' : ''}`} />
        )}
        <Icon className="h-4 w-4 flex-none text-neutral-500" />
        <span className="truncate text-sm">{node.name}</span>
      </button>
      {!isLeaf && expanded && node.children && (
        <ul role="group">
          {node.children.map((c) => <TreeNode key={c.id} node={c} depth={depth + 1} />)}
        </ul>
      )}
    </li>
  );
}

