// components/AutosizeTextarea.tsx
import { useEffect, useRef, forwardRef } from 'react';

export const AutosizeTextarea = forwardRef<HTMLTextAreaElement, React.TextareaHTMLAttributes<HTMLTextAreaElement> & { minRows?: number; maxRows?: number }>(({ minRows = 2, maxRows = 10, onChange, value, ...rest }, externalRef) => {
  const internalRef = useRef<HTMLTextAreaElement>(null);
  const ref = (externalRef as React.RefObject<HTMLTextAreaElement>) || internalRef;

  const autoGrow = () => {
    const ta = ref.current;
    if (!ta) return;
    ta.style.height = 'auto';
    const lineHeight = parseFloat(getComputedStyle(ta).lineHeight);
    const maxHeight = lineHeight * maxRows + parseFloat(getComputedStyle(ta).paddingTop) * 2;
    ta.style.height = `${Math.min(ta.scrollHeight, maxHeight)}px`;
  };

  useEffect(autoGrow, [value]);

  return (
    <textarea
      ref={ref}
      value={value}
      onChange={(e) => { onChange?.(e); autoGrow(); }}
      rows={minRows}
      style={{ resize: 'none', overflowY: 'auto' }}
      className="w-full rounded border px-3 py-2 text-base focus:outline-2 focus:outline-blue-500"
      {...rest}
    />
  );
});
AutosizeTextarea.displayName = 'AutosizeTextarea';

// components/AvatarUpload.tsx
import { useState, useRef } from 'react';
import { Camera } from 'lucide-react';

export function AvatarUpload({ currentSrc, onUpload }: { currentSrc?: string; onUpload: (blob: Blob) => void }) {
  const [preview, setPreview] = useState(currentSrc);
  const inputRef = useRef<HTMLInputElement>(null);

  const onFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Show preview
    const url = URL.createObjectURL(file);
    setPreview(url);

    // Compress to ~256x256 for upload
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      const SIZE = 256;
      canvas.width = SIZE;
      canvas.height = SIZE;
      const ctx = canvas.getContext('2d')!;
      // Square crop center
      const min = Math.min(img.width, img.height);
      const sx = (img.width - min) / 2;
      const sy = (img.height - min) / 2;
      ctx.drawImage(img, sx, sy, min, min, 0, 0, SIZE, SIZE);
      canvas.toBlob((blob) => blob && onUpload(blob), 'image/webp', 0.9);
    };
    img.src = url;
  };

  return (
    <div className="flex flex-col items-center gap-3">
      <div className="relative">
        <img
          src={preview || '/placeholder-avatar.png'}
          alt=""
          className="h-24 w-24 rounded-full object-cover bg-neutral-200"
        />
        <button
          type="button"
          onClick={() => inputRef.current?.click()}
          aria-label="Change photo"
          className="absolute bottom-0 right-0 flex h-9 w-9 items-center justify-center rounded-full bg-black text-white shadow"
        ><Camera className="h-4 w-4" /></button>
      </div>
      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        capture="user"
        onChange={onFileChange}
        className="sr-only"
      />
    </div>
  );
}

// hooks/useHistoryModal.ts
import { useEffect } from 'react';

export function useHistoryModal(open: boolean, onClose: () => void) {
  useEffect(() => {
    if (!open) return;

    // Push state when modal opens
    const state = { modal: true };
    history.pushState(state, '', location.href);

    const onPop = () => {
      onClose();
    };

    window.addEventListener('popstate', onPop);
    return () => {
      window.removeEventListener('popstate', onPop);
      // If modal closed without back gesture, pop the state we pushed
      if (history.state?.modal) {
        history.back();
      }
    };
  }, [open, onClose]);
}

