// components/UniversalDropZone.tsx
import { useState } from 'react';
import { Upload } from 'lucide-react';

export function UniversalDropZone({ onFiles }: { onFiles: (files: File[]) => void }) {
  const [over, setOver] = useState(false);

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setOver(false);
    const files = Array.from(e.dataTransfer.files);
    if (files.length) onFiles(files);
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const items = Array.from(e.clipboardData.items);
    const files = items.filter((i) => i.kind === 'file').map((i) => i.getAsFile()!).filter(Boolean);
    if (files.length) onFiles(files);
  };

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setOver(true); }}
      onDragLeave={() => setOver(false)}
      onDrop={handleDrop}
      onPaste={handlePaste}
      tabIndex={0}
      className={`
        flex flex-col items-center justify-center gap-2
        min-h-32 rounded-lg border-2 border-dashed p-6
        ${over ? 'border-blue-500 bg-blue-50' : 'border-neutral-300'}
      `}
    >
      <Upload className="h-8 w-8 text-neutral-400" aria-hidden />
      <p className="text-sm text-neutral-600">Drop files here, paste, or <label className="text-blue-600 underline cursor-pointer">browse<input type="file" multiple className="sr-only" onChange={(e) => onFiles(Array.from(e.target.files ?? []))} /></label></p>
    </div>
  );
}

// components/VirtualSpreadsheet.tsx
import { useRef, useEffect, useState } from 'react';

const ROW_HEIGHT = 32;
const COL_WIDTH = 100;
const FROZEN_COLS = 1;
const FROZEN_ROWS = 1;

export function VirtualSpreadsheet({ rows, cols }: { rows: number; cols: number }) {
  const containerRef = useRef<HTMLDivElement>(null);
  const [scrollPos, setScrollPos] = useState({ x: 0, y: 0 });
  const [size, setSize] = useState({ w: 0, h: 0 });

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const onScroll = () => setScrollPos({ x: el.scrollLeft, y: el.scrollTop });
    el.addEventListener('scroll', onScroll, { passive: true });
    const ro = new ResizeObserver(() => setSize({ w: el.clientWidth, h: el.clientHeight }));
    ro.observe(el);
    return () => { el.removeEventListener('scroll', onScroll); ro.disconnect(); };
  }, []);

  const startRow = Math.floor(scrollPos.y / ROW_HEIGHT);
  const endRow = Math.min(rows, Math.ceil((scrollPos.y + size.h) / ROW_HEIGHT) + 1);
  const startCol = Math.floor(scrollPos.x / COL_WIDTH);
  const endCol = Math.min(cols, Math.ceil((scrollPos.x + size.w) / COL_WIDTH) + 1);

  const visibleRows: number[] = [];
  for (let r = startRow; r < endRow; r++) visibleRows.push(r);
  const visibleCols: number[] = [];
  for (let c = startCol; c < endCol; c++) visibleCols.push(c);

  return (
    <div ref={containerRef} className="relative overflow-auto w-full h-full bg-white">
      <div style={{ width: cols * COL_WIDTH, height: rows * ROW_HEIGHT }}>
        {/* Frozen header row */}
        <div className="sticky top-0 z-20 flex bg-neutral-100 border-b">
          {visibleCols.map((c) => (
            <div
              key={c}
              style={{ width: COL_WIDTH, height: ROW_HEIGHT, position: 'absolute', left: c * COL_WIDTH }}
              className="flex items-center justify-center text-xs font-medium border-r"
            >{String.fromCharCode(65 + c)}</div>
          ))}
        </div>
        {/* Cells */}
        {visibleRows.map((r) => visibleCols.map((c) => (
          <div
            key={`${r}-${c}`}
            style={{
              position: 'absolute',
              top: r * ROW_HEIGHT,
              left: c * COL_WIDTH,
              width: COL_WIDTH,
              height: ROW_HEIGHT,
            }}
            className="flex items-center px-2 text-sm border-r border-b"
          >{`R${r}C${c}`}</div>
        )))}
      </div>
    </div>
  );
}
