import { useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { AdaptiveDialog } from './AdaptiveDialog'; // from responsive-015

export function AdaptiveEditableCell({ value, onChange, label }: { value: string; onChange: (v: string) => void; label: string }) {
  const bp = useBreakpoint();
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState(value);

  if (bp === 'mobile') {
    return (
      <>
        <button
          type="button"
          onClick={() => { setDraft(value); setEditing(true); }}
          className="block w-full text-left px-2 py-2 min-h-11 hover:bg-blue-50"
        >{value || <span className="text-neutral-400">—</span>}</button>
        <AdaptiveDialog
          open={editing}
          onClose={() => setEditing(false)}
          title={`Edit ${label}`}
          primaryAction={{ label: 'Save', onClick: () => { onChange(draft); setEditing(false); } }}
        >
          <input
            type="text"
            value={draft}
            onChange={(e) => setDraft(e.target.value)}
            autoFocus
            aria-label={label}
            className="w-full min-h-12 rounded border px-3 text-base"
          />
        </AdaptiveDialog>
      </>
    );
  }

  // Desktop: inline edit (per responsive-117)
  if (editing) {
    return (
      <input
        type="text"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={() => { onChange(draft); setEditing(false); }}
        onKeyDown={(e) => {
          if (e.key === 'Enter') { onChange(draft); setEditing(false); }
          if (e.key === 'Escape') setEditing(false);
        }}
        autoFocus
        aria-label={label}
        className="w-full h-full px-2 outline-2 outline-blue-500"
      />
    );
  }

  return (
    <button
      type="button"
      onDoubleClick={() => { setDraft(value); setEditing(true); }}
      onKeyDown={(e) => { if (e.key === 'F2' || e.key === 'Enter') { setDraft(value); setEditing(true); } }}
      tabIndex={0}
      className="block w-full text-left px-2 py-1 min-h-9 hover:bg-blue-50"
    >{value || <span className="text-neutral-400">—</span>}</button>
  );
}

